private IllegalArgumentException wrongBuf(int releasedLength, int srcLength) {
    // sanity check failed; trying to return different, smaller buffer.
    return new IllegalArgumentException("Trying to release buffer smaller than original (" + releasedLength + " <= " + srcLength + ")");
}
